/* map q09 (129 mục) — engine-API đợt 1154-1169 Ch.1169 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q09"]=window.__LIBQ["tien-nghich"]["q09"]||{};window.__LIBQ["tien-nghich"]["q09"]["map"]={"updatedAt":"2026-07-11","count":129,"nodes":[{"id":"khe-khong-gian-than-the-do-ti","name":"Khe không gian chứa thân thể Đồ Ti","cn":"","capDo":"khac","parentId":null,"blurb":"Khe không gian bên ngoài thân thể Đồ Ti, chứa thân thể Cổ Thần to bằng mấy tu chân tinh hợp lại.","detail":"Khe không gian nằm bên ngoài thân thể Đồ Ti. Bên trong chứa thân thể Đồ Ti to lớn bằng mấy tu chân tinh hợp lại. Cơn lốc xoáy mới (xuất hiện sau khi Thác Sâm biến mất) dẫn tới khe không gian này. Lão già áo đen và Vương Lâm bước vào lốc xoáy để tới đây. Cuối chương, thân thể Đồ Ti ngón tay khẽ động, đôi mắt mở ra lần đầu tiên.","theLucLienQuan":["Cổ Thần"],"nguon":["@c1064"]},{"id":"nguyet-tinh-ngoai-chu-tuoc","name":"Nguyệt tinh (ngoài Chu Tước Tinh)","cn":"","capDo":"tinh-cau","parentId":"chu-tuoc-tinh-map","blurb":"Nguyệt tinh ngoài Chu Tước Tinh, nơi bổn tôn Vương Lâm ẩn thân trong một ngọn núi tầm thường. Sau khi phân thân bị diệt, hắn tỉnh dậy ở đây rồi bỏ trốn.","detail":"Nguyệt tinh xoay quanh Chu Tước Tinh, bên trong có ngọn núi nơi bổn tôn Vương Lâm bố trí trận pháp ẩn thân. Sau khi phân thân bị Thác Sâm tiêu diệt, bổn tôn tỉnh dậy tại đây, thu nữ thi vào khe trữ vật rồi phá hủy trận pháp, thi triển Súc Địa Thành Thốn rời đi.","theLucLienQuan":[],"nguon":["@c1066"]},{"id":"tinh-cau-bo-di-duong-lui","name":"Tinh cầu bỏ đi (đường lui của Vương Lâm)","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu hoang mà Vương Lâm đã bố trí trận pháp làm đường lui trước khi đến Tứ Thánh Tông gặp Thanh Long Thánh Hoàng.","detail":"Một tinh cầu bỏ đi mà Vương Lâm đã lặng lẽ bố trí trận pháp trước khi đến Tứ Thánh Tông. Sau khi bỏ trốn khỏi Liên minh Tinh Vực, hắn chạy đến đây làm nơi trú chân tạm.","theLucLienQuan":[],"nguon":["@c1066"]},{"id":"lien-minh-tinh-vuc","name":"Liên minh Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Liên minh các thế lực tinh vực mà Vương Lâm từng hoạt động. Sau sự kiện Thác Sâm, hắn nhận ra vĩnh viễn không thể quay về trừ phi có sức mạnh đối phó.","detail":"Khu vực liên minh tinh vực nơi Chu Tước Tinh và các thế lực như Tứ Thánh Tông tọa lạc. Sau khi phân thân bị Thác Sâm tiêu diệt và bổn tôn bỏ trốn, Vương Lâm nhận ra hắn vĩnh viễn không thể quay về Liên minh Tinh Vực trừ phi có đủ sức mạnh đối phó Cổ Thần.","theLucLienQuan":[],"nguon":["@c1066","@c1104"]},{"id":"van-hai-tinh-vuc","name":"Vân Hải Tinh Vực","cn":"云海星域","capDo":"tinh-cau","parentId":"phong-gioi","blurb":"Tinh vực của Phong Giới, lớn nhất trong tứ đại Tiên Giới, tràn ngập tinh vụ vĩnh hằng. Chia 9 bậc đồng tâm theo độ dày sương mù.","detail":"Không phân phương vị Đông Tây Nam Bắc mà chia chín bậc (chín hình tròn không quy tắc, bậc 1 ngoài cùng, bậc 9 trong cùng). Tu chân tinh dưới 100, tập trung từ tầng 7 trở lên; phần còn lại là đại lục trôi nổi đại diện tinh phái. Tu sĩ đại thần thông nếu không có tinh đồ chuẩn xác sẽ bị lạc vĩnh viễn trong tinh vụ.","theLucLienQuan":["Vân Hải Tinh Vực"],"nguon":["@c1067","@c1103","@c1126"]},{"id":"dai-luc-mac-la","name":"Đại lục Mạc La","cn":"摩罗大陆","capDo":"khac","parentId":"van-hai-tinh-vuc","blurb":"Đại lục nằm ở bậc thứ năm Vân Hải Tinh Vực, ẩn hiện trong tinh vụ nồng đậm. Trung tâm có tòa tháp đen cao vút tỏa ánh sáng bao phủ toàn đại lục, ngăn sương mù xâm nhập.","detail":"Phía bắc có rừng sâu với trận pháp truyền tống tiếp nhận từ Liên Minh Tinh Vực. Tòa tháp đen trung tâm phát ra ánh sáng nhẹ bao phủ cả đại lục tạo vùng quang đãng. Là đích đến của Vương Lâm khi rời Liên Minh Tinh Vực.","theLucLienQuan":[],"nguon":["@c1067"]},{"id":"toa-thap-den-mac-la","name":"Tòa tháp đen (trung tâm Mạc La)","cn":"","capDo":"khac","parentId":"dai-luc-mac-la","blurb":"Tòa tháp đen cao vút ở trung tâm đại lục Mạc La, tỏa ánh sáng nhẹ bao phủ cả đại lục, ngăn sương mù xâm nhập.","detail":"Ánh sáng từ tháp tạo vùng quang đãng cho toàn bộ đại lục Mạc La, cho phép cư dân sống mà không bị tinh vụ che phủ.","theLucLienQuan":[],"nguon":["@c1067"]},{"id":"bon-dia-quy-nguyen-tong","name":"Bồn địa Quy Nguyên Tông","cn":"","capDo":"khac","parentId":"dai-luc-mac-la","blurb":"Vùng bồn địa bao quanh bởi dãy núi hình tròn ở phía đông đại lục Mạc La, nơi Quy Nguyên Tông tọa lạc.","detail":"Bên trong là vùng đất bằng phẳng với nhà cửa đệ tử khắp nơi. Trung tâm có tám cây cột đá cao vạn trượng, trên đỉnh treo lơ lửng một đạo quán khổng lồ — nơi chưởng môn tu luyện và hấp hối.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1068"]},{"id":"khu-rung-phia-bac-mac-la","name":"Khu rừng phía Bắc đại lục Mạc La","cn":"","capDo":"khac","parentId":"dai-luc-mac-la","blurb":"Khu rừng ở phía Bắc đại lục Mạc La, nơi đặt Truyền Tống Trận thông đến Liên Minh Tinh Vực.","detail":"Vương Lâm xuất hiện tại đây qua Truyền Tống Trận giữa cơn mưa đêm, chính thức bước vào Vân Hải Tinh Vực. Thần thức chưởng môn Quy Nguyên Tông phát hiện hắn tại vị trí này.","theLucLienQuan":[],"nguon":["@c1068"]},{"id":"bac-thuy-thon","name":"Bắc Thủy Thôn","cn":"","capDo":"khac","parentId":"dai-luc-mac-la","blurb":"Thôn nhỏ phía Bắc đại lục Mạc La, cách khu rừng chưa đến ngàn dặm. Dân sống bằng trồng trọt và săn bắn, mùa mưa bắt ếch trong rừng.","detail":"Nơi Vương Lâm ẩn thân một tháng với danh tính Tằng Ngưu, làm lang trung chữa bệnh và thợ khắc gỗ. Được đại hán Vũ Đại cho ở nhờ sau khi cứu Lão Tam khỏi rắn độc. Tu sĩ Triệu Ngọc thuộc Quy Nguyên Tông đến đây tuyển đệ tử.","theLucLienQuan":[],"nguon":["@c1069"]},{"id":"nam-uyen-quy-nguyen-tong","name":"Nam Uyển (Quy Nguyên Tông)","cn":"南苑","capDo":"khac","parentId":"bon-dia-quy-nguyen-tong","blurb":"Khu vực phía nam Quy Nguyên Tông, có bồn địa lầu các, dãy núi, rừng bốn mùa xanh tốt, tòa nhà đỏ chỗ ở Lữ Yên Phi và khu vườn dược thảo chứa nhiều loại cây đã tuyệt chủng.","detail":"Nam Uyển nằm ở phía nam Quy Nguyên Tông, có bồn địa với lầu các, dãy núi phía nam trải rộng. Trên đỉnh núi có khu rừng bốn mùa xanh tốt, bên trong có tòa nhà màu đỏ điêu khắc tượng phượng hoàng — chỗ ở của Lữ Yên Phi. Sát Nam Uyển có khu vườn dược thảo tinh xảo chứa nhiều loại dược thảo đã tuyệt chủng ở cả Liên Minh Tinh Vực lẫn La Thiên Tinh Vực.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1070"]},{"id":"van-hai-linh-vuc","name":"Vân Hải Lĩnh Vực","cn":"云海领域","capDo":"vuc","parentId":"van-hai-tinh-vuc","blurb":"Khu vực trong Vân Hải Tinh Vực, nơi sinh sống của loại linh thú vượn đen đặc biệt đã tu đạo hơn ba ngàn năm, hồn phách được dùng luyện Nhập Tử Ly Hồn Đan.","detail":"Vân Hải Lĩnh Vực là nơi cư ngụ của loại linh thú vượn đen có tuổi thọ hơn ba ngàn năm, đã có cảm ngộ sâu sắc về trời đất. Hồn phách của chúng được thu thập và phối hợp thuật luyện đan, hóa thành Nhập Tử Ly Hồn Đan — loại đan dược dùng hồn phách linh thú trợ giúp tu sĩ cảm ngộ ý cảnh để đột phá cảnh giới.","theLucLienQuan":[],"nguon":["@c1072"]},{"id":"day-nui-phia-nam-mac-la","name":"Dãy núi phía nam (tẩm cung sư tôn)","cn":null,"capDo":"khac","parentId":"dai-luc-mac-la","blurb":"Dãy núi phía nam trên đại lục Mạc La, nơi tẩm cung của sư tôn Lữ Yên Phi tọa lạc.","detail":"Dãy núi nằm ở phía nam đại lục Mạc La, nơi Lữ Yên Phi — sư tôn của Tôn Vân — đặt tẩm cung. Sau khi hấp thu hồn lực Nhập Tử Ly Hồn Đan và nhớ lại di ngôn sư tổ, Tôn Vân lập tức bay tới đây để gặp sư tôn.","theLucLienQuan":["quy-nguyen-tong"],"nguon":["@c1072"]},{"id":"dao-quan-quy-nguyen-tong","name":"Đạo quán giữa không trung (Quy Nguyên Tông)","cn":"","capDo":"khac","parentId":"bon-dia-quy-nguyen-tong","blurb":"Đạo quán treo lơ lửng trên tám cây cột đá lớn giữa không trung bồn địa Quy Nguyên Tông, bên trong có khe không gian phát tử quang và giá đặt ba di bảo lão tổ, Tử Mục Mãng canh giữ.","detail":"Đạo quán treo giữa không trung trên tám cây cột đá lớn trong bồn địa Quy Nguyên Tông. Bên trong có một khe không gian rất lớn phát tử quang chiếu tím cả gian phòng, phía sau khe là một cái giá có cấm chế, đặt ba vật di bảo lão tổ: thanh trường kiếm, ngọc giản và Ly Hồn Đan cấp tám. Tử Mục Mãng (Khuy Niết hậu kỳ) từ khe không gian chui ra canh giữ. Vương Lâm đêm đột nhập, phá cấm chế nghiên cứu ngọc giản.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1073"]},{"id":"dinh-dong-uyen","name":"Đỉnh Đông Uyển","cn":"","capDo":"khac","parentId":"bon-dia-quy-nguyen-tong","blurb":"Đỉnh núi của trưởng lão Lý Hướng Đông trong Quy Nguyên Tông.","detail":"Một trong bốn đỉnh núi của tứ đại trưởng lão Quy Nguyên Tông, nơi Lý Hướng Đông trú ngụ.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1074"]},{"id":"dai-luc-tim-tu-dao-tong","name":"Đại lục tím (căn cứ Tử Đạo Tông)","cn":"","capDo":"dai-luc","parentId":"van-hai-tinh-vuc","blurb":"Đại lục màu tím ở tầng thứ năm Vân Hải Tinh Vực, lớn gấp ba đại lục Mạc La, hình dạng như hung thú. Căn cứ của Tử Đạo Tông, có bốn ngọn tháp đen phòng hộ.","detail":"Đại lục màu tím nằm ở tầng thứ năm Vân Hải Tinh Vực, kích thước lớn hơn đại lục Mạc La ba lần, trông như hung thú đứng nhìn tinh không. Bốn ngọn tháp đen tỏa ánh sáng bao phủ toàn bộ đại lục tạo hệ thống phòng hộ. Là căn cứ địa của Tử Đạo Tông.","theLucLienQuan":["Tử Đạo Tông"],"nguon":["@c1075"]},{"id":"tu-van-hai","name":"Tử Vân Hải","cn":"","capDo":"khac","parentId":"van-hai-tinh-vuc","blurb":"Nơi đặt Thiên Âm Phiên — bảo vật tông môn của Tử Đạo Tông. Lô Địch muốn tới đây lấy Thiên Âm Phiên trước khi đến Quy Nguyên Tông nhưng chưa kịp.","detail":"Tử Vân Hải nằm trong Vân Hải Tinh Vực, là nơi cất giữ Thiên Âm Phiên của Tử Đạo Tông. Lô Địch dự định đến đây lấy bảo vật để phong ấn hồn phách nữ tử nuôi âm tiên.","theLucLienQuan":["Tử Đạo Tông"],"nguon":["@c1076"]},{"id":"dong-uyen-quy-nguyen-tong","name":"Đông Uyển (Quy Nguyên Tông)","cn":"","capDo":"khac","parentId":"bon-dia-quy-nguyen-tong","blurb":"Khu vực đặt đan phòng của Quy Nguyên Tông, có lò luyện, có thể dẫn dắt địa hỏa, có trận pháp phòng hộ chống đan tạc.","detail":"Khu vực trong Quy Nguyên Tông nơi đặt đan phòng chính thức. Có lò luyện chuyên dụng, có thể dẫn dắt địa hỏa từ lòng đất, bên ngoài có trận pháp phòng hộ chống lực xung kích khi đan tạc. Tôn Vân khuyên Vương Lâm đến đây luyện đan nhưng bị từ chối.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1077"]},{"id":"dai-luc-hoang-da-ngoai-tinh-vuc","name":"Đại lục hoang dã ngoài tinh vực","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi tinh vụ bao phủ, Vụ Trung Hoa sinh trưởng tại đây, tinh vụ càng đậm đặc hoa càng nhiều.","detail":"Đại lục hoang dã bên ngoài tinh vực, bị tinh vụ bao phủ quanh năm. Vụ Trung Hoa chỉ sinh trưởng tại đây, nơi tinh vụ càng đậm đặc thì hoa càng nhiều. Tu sĩ bình thường khó tiếp cận.","theLucLienQuan":[],"nguon":["@c1077"]},{"id":"man-hoang-dai-luc","name":"Man Hoang đại lục","cn":"蛮荒大陆","capDo":"tinh-cau","parentId":"van-hai-tinh-vuc","blurb":"Tinh cầu trong tinh vực cấp năm gần Mạc La đại lục, không có hắc tháp bảo hộ, bị tinh vụ bao phủ hoàn toàn, là nơi tụ tập hung thú khát máu và có nhiều dược thảo quý.","detail":"Man Hoang đại lục nằm trong Vân Hải tinh vực, gần Mạc La đại lục. Cấu tạo giống Lôi Vũ. Không có hắc tháp bảo hộ nên bị tinh vụ bao phủ hoàn toàn, thần thức bị hạn chế nghiêm trọng. Mặt đất là cát đen bóng, sương mù dày đặc bốn phía, tiếng gầm rống mãnh thú vang vọng. Tồn tại dấu tích thành trì phàm nhân đổ nát với vết máu khô trên tường. Nơi đây tụ tập nhiều hung thú khát máu và có nhiều dược thảo quý, tu sĩ ít lui tới. Được đánh dấu nguy hiểm trên bản đồ tinh cầu ngọc giản Quy Nguyên Tông.","theLucLienQuan":[],"nguon":["@c1078"]},{"id":"son-coc-man-hoang","name":"Sơn cốc (Man Hoang đại lục)","cn":"","capDo":"khac","parentId":"man-hoang-dai-luc","blurb":"Sơn cốc tràn đầy sương mù và tử hồn trên Man Hoang đại lục, nơi Thi Lạc Hình bị lão bà Ngũ Độc Môn dùng trận pháp tám đầu lâu vây khốn.","detail":"Sơn cốc nằm trên Man Hoang đại lục, tràn đầy sương mù và tử hồn bị trận pháp dẫn động. Thi Lạc Hình cùng bốn đệ tử còn sống bị vây hãm tại đây bởi lão bà Ngũ Độc Môn.","theLucLienQuan":["Ngũ Độc Môn"],"nguon":["@c1080"]},{"id":"khu-vuc-trung-tam-man-hoang","name":"Khu vực trung tâm Man Hoang đại lục","cn":"","capDo":"vuc","parentId":"man-hoang-dai-luc","blurb":"Khu vực trung tâm Man Hoang đại lục, nơi tồn tại mãnh thú cấp bậc rất cao, toàn sơn cốc sương mù với khí tức âm trầm uy áp.","detail":"Không nhiều núi nhưng khắp nơi là sơn cốc với sương mù lượn lờ, khí tức âm trầm uy áp. Kỳ lạ là mọi mãnh thú bên trong dường như đã biến mất. Ngũ Độc Môn bày trận pháp tám đầu lâu khổng lồ hấp thu tử hồn bao vây sơn cốc tại đây.","theLucLienQuan":["Ngũ Độc Môn"],"nguon":["@c1081"]},{"id":"tap-anh-cac","name":"Tập Anh Các","cn":"","capDo":"khac","parentId":"hoa-thanh-tong-dia-ban","blurb":"Nơi trong Hoa Thanh Tông lưu giữ thẻ sinh mệnh của đệ tử.","detail":"Tập Anh Các là địa điểm bên trong Hoa Thanh Tông, nơi thẻ sinh mệnh đệ tử được bảo quản. Thẻ sinh mệnh của Thi Lạc Hình trong Tập Anh Các đã vỡ vụn, xác nhận hắn tử vong.","theLucLienQuan":["Hoa Thanh Tông"],"nguon":["@c1084"]},{"id":"khe-nut-khong-gian-pha-thien-tong","name":"Khe nứt không gian (Phá Thiên Tông phát hiện)","cn":"","capDo":"khac","parentId":null,"blurb":"Khe nứt không gian dày đặc cấm chế mà Phá Thiên Tông phát hiện mười vạn tám ngàn năm trước, bên trong chứa bộ hài cốt bí ẩn kèm ba bảo vật.","detail":"Mười vạn tám ngàn năm trước, Phá Thiên Tông tập hợp tu sĩ phá cấm chế tiến vào khe nứt không gian này, tìm được bộ hài cốt cùng ba vật phẩm (viên đan dược, thanh tàn kiếm, mảnh xương thú). Tin tức bị lộ dẫn đến đại chiến toàn Vân Hải Tinh Vực.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1084"]},{"id":"tu-tinh-vuc","name":"Tụ tinh vực","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh vực được Tiền Quý Chung nhắc đến trước khi chết, suy đoán Vương Lâm có thể đến từ nơi này.","detail":"Tiền Quý Chung suy đoán Vương Lâm là người từ Tụ tinh vực vì biết rõ chuyện Phá Thiên Tông và vương pháp luyện đan.","theLucLienQuan":[],"nguon":["@c1086"]},{"id":"van-hai-tinh-vuc-cap-chin","name":"Vân Hải tinh vực cấp chín","cn":"","capDo":"tinh-cau","parentId":"van-hai-tinh-vuc","blurb":"Nơi sâu nhất Vân Hải tinh vực, sương mù nồng nặc giới hạn thần thức Toái Niết chỉ 50 trượng, có mãnh thú hùng mạnh nhất tinh vực. Bảy tu chân tinh xếp hình Bắc Đẩu bao phủ tầng phòng hộ, là tinh vực cấp chín nơi Phá Thiên Tông tọa lạc.","detail":"Nằm ở nơi sâu nhất Vân Hải tinh vực, sương mù nồng nặc che khuất thần thức ngay cả tu sĩ Toái Niết (chỉ bao phủ 50 trượng). Có mãnh thú hùng mạnh nhất tinh vực ẩn trong sương mù nhưng không dám đến gần bảy tu chân tinh xếp hình Bắc Đẩu. Trên tu chân tinh có thảo nguyên rộng lớn với pho tượng tu sĩ khổng lồ chỉ tay lên trời, trợn mắt mắng trời xanh — bên trong pho tượng là sư tổ Phá Thiên Tông.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1090"]},{"id":"bay-tu-chan-tinh-bac-dau","name":"Bảy tu chân tinh hình Bắc Đẩu","cn":"","capDo":"tinh-cau","parentId":"van-hai-tinh-vuc-cap-chin","blurb":"Bảy tu chân tinh xếp theo hình sao Bắc Đẩu ở tinh vực cấp chín, bao phủ tầng phòng hộ liên kết, trên đó có thảo nguyên và pho tượng tu sĩ khổng lồ. Là nơi đặt căn cứ Phá Thiên Tông.","detail":"Nằm ở rìa tinh vực cấp chín, bảy tu chân tinh xếp hình sao Bắc Đẩu, mỗi tinh cầu đều có tầng phòng hộ liên kết nhau. Trên một tu chân tinh có thảo nguyên rộng lớn và pho tượng tu sĩ khổng lồ chỉ tay lên trời.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1090"]},{"id":"khu-vuon-phia-nam-quy-nguyen-tong","name":"Khu vườn phía nam Quy Nguyên Tông (cấm địa)","cn":"","capDo":"khac","parentId":"bon-dia-quy-nguyen-tong","blurb":"Cấm địa của Quy Nguyên Tông, nơi Vương Lâm ẩn cư, có dược viên. Khí tức bên trong như mãnh thú hùng mạnh tồn tại.","detail":"Khu vườn phía nam Quy Nguyên Tông là cấm địa, nơi Vương Lâm ẩn cư. Bên trong có dược viên, khí tức khác biệt hoàn toàn với bên ngoài, như có mãnh thú hùng mạnh tồn tại. Chỉ bùng khí tức cũng đủ làm Trừu Hải (Tịnh Niết sơ kỳ) toàn thân tuôn máu. Trừu Hải xâm nhập nơi đây và bị Vương Lâm đánh trọng thương.","theLucLienQuan":["Quy Nguyên Tông"],"nguon":["@c1092"]},{"id":"mac-la-dai-luc","name":"Mạc La đại lục","cn":"","capDo":"chau","parentId":"van-hai-tinh","blurb":"Đại lục nơi Quy Nguyên Tông tọa lạc, là điểm đến của đoàn Tử Đạo Tông trong chương 1094.","detail":"Lô Vân Tòng dẫn hơn ba mươi đệ tử hạch tâm của Tử Đạo Tông cưỡi hổ thú hướng về Mạc La đại lục. Khi còn khoảng nửa ngày đường tới nơi, Lý Thiến Mai xuất hiện chặn đường và đặt ba vấn đề cho hắn.","theLucLienQuan":["Quy Nguyên Tông","Tử Đạo Tông"],"nguon":["@c1094"]},{"id":"bong-lai-dai-luc","name":"Bồng Lai đại lục","cn":"","capDo":"khac","parentId":null,"blurb":"Bồng Lai đại lục nằm trong tinh vực cấp năm, thực chất là một tu chân tinh có hình như vầng trăng khuyết. Đây là địa bàn trọng yếu của Bảo Ngọc Tông và là nơi mở chợ lớn ba mươi năm một lần.","detail":"Bồng Lai rộng hơn Mạc La đại lục rất nhiều, bên ngoài có tầng phòng hộ phát sáng đẩy sương mù. Nơi đây nổi tiếng với chợ giao dịch, đấu giá và Bồng Lai Loạn Pháp, thu hút nhiều tu sĩ từ tinh vực cấp cao.","theLucLienQuan":["Bảo Ngọc Tông","Quỷ Tông"],"nguon":["@c1098","@c1108"]},{"id":"tu-chan-tinh","name":"Tu chân tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh là loại thiên thể rất hiếm tại Vân Hải tinh vực. Chỉ tông phái có thực lực cường hãn mới có thể nắm giữ loại địa bàn này.","detail":"Bồng Lai đại lục thực chất là một tu chân tinh chứ không phải đại lục thông thường. Việc Bảo Ngọc Tông nắm được một nửa Bồng Lai cho thấy địa vị của tông này tại tinh vực cấp năm.","theLucLienQuan":["Bảo Ngọc Tông"],"nguon":["@c1098"]},{"id":"khong-gian-dut-gay","name":"Không gian đứt gãy","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian đứt gãy nằm ở vùng sâu tinh vực cấp chín và liên quan đến một tinh vực thần bí. Đây là nơi mãnh thú cực mạnh từ nơi khác đi ra.","detail":"Sau cuộc nổi loạn mãnh thú lần thứ nhất, Thần Tông phái đệ tử tới phòng thủ nơi này. Qua nhiều ngàn năm, nhóm đệ tử ấy tách thành Yêu Tông nhưng vẫn tiếp tục canh giữ, việc chém giết còn kéo dài đến hiện tại.","theLucLienQuan":["Thần Tông","Yêu Tông"],"nguon":["@c1098"]},{"id":"tinh-vuc-than-bi","name":"Tinh vực thần bí","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực thần bí nằm phía sau không gian đứt gãy ở vùng sâu tinh vực cấp chín. Đây là nguồn gốc của các mãnh thú cực mạnh từng gây ra cuộc nổi loạn.","detail":"Lý Thiến Mai chỉ biết nơi này có liên quan đến không gian đứt gãy, từng có mãnh thú rất mạnh và ba tồn tại tu thành hình người đi ra. Vương Lâm sau khi nghe chuyện đã suy tư về vị trí thật sự của tinh vực này.","theLucLienQuan":["Yêu Tông","Thần Tông"],"nguon":["@c1098"]},{"id":"khu-cho-bong-lai","name":"Khu chợ Bồng Lai","cn":"","capDo":"khac","parentId":"bong-lai-dai-luc","blurb":"Khu chợ nằm ở phía đông Bồng Lai đại lục, do Bảo Ngọc Tông tổ chức và có nhiều tu sĩ ra vào giao dịch. Nơi này gồm nhiều tảng đá khổng lồ hình mũi dùi trôi nổi, mỗi tảng đá có thành trì và trận pháp duy trì.","detail":"Các tảng đá hình mũi dùi xoay quanh một khối đá trung tâm, có tiên âm vang vọng và linh thú bay lượn. Mỗi khối đá đều có trận pháp lớn tiêu hao linh thạch để duy trì trạng thái trôi nổi; Lý Thiến Mai nhận xét nơi này chỉ có tiên hình mà không có tiên khí.","theLucLienQuan":["Bảo Ngọc Tông"],"nguon":["@c1099"]},{"id":"toa-thanh-trung-tam-bong-lai","name":"Tòa thành trung tâm Bồng Lai","cn":"","capDo":"thanh","parentId":"khu-cho-bong-lai","blurb":"Tòa thành trung tâm nằm trên khối đá khổng lồ hình trùy bay lơ lửng trong khu chợ Bồng Lai. Nơi này lớn hơn các thành thị bên ngoài nhiều lần và dẫn tới trường đấu thú cùng buổi đấu giá tư nhân.","detail":"Âu Dương Long dẫn Vương Lâm vào tòa thành lớn ở vị trí trung tâm khu chợ, được xây trên khối đá hình trùy khổng lồ bay lơ lửng. Bên trong có đường dẫn tới trường đấu thú và nơi sư thúc của Âu Dương Long chủ trì buổi đấu giá tư nhân.","theLucLienQuan":[],"nguon":["@c1101"]},{"id":"truong-dau-thu-bong-lai","name":"Trường đấu thú Bồng Lai","cn":"","capDo":"khac","parentId":"toa-thanh-trung-tam-bong-lai","blurb":"Trường đấu thú Bồng Lai là nơi các linh thú chém giết nhau trước sự chứng kiến của tu sĩ. Khu vực này có đài cao chu vi vạn trượng, thềm đá cho người xem và lối đi treo trên bầu trời dành cho khách đặc biệt.","detail":"Âu Dương Long đưa Vương Lâm đi qua lối đi treo trên bầu trời để xuống trường đấu thú. Nơi này có đài cao rộng lớn, xung quanh là thềm đá cho tu sĩ quan sát cảnh linh thú chém giết, đồng thời nối với khu vực riêng tư trước buổi đấu giá.","theLucLienQuan":[],"nguon":["@c1101"]},{"id":"phong-dau-gia-tu-nhan-trong-khu-cho","name":"Phòng đấu giá tư nhân trong khu chợ","cn":"","capDo":"khac","parentId":"khu-cho-bong-lai","blurb":"Phòng đấu giá tư nhân trong khu chợ là nơi tụ họp riêng của tu sĩ cấp Toái Niết. Căn phòng có sàn trong suốt nhìn xuống đài đấu thú và được nối với bên ngoài bằng cánh cửa đá có sóng rung động.","detail":"Đây là căn phòng hơn mười trượng nằm trong khu chợ Bồng Lai, nơi Thương Tùng Tử mở buổi tụ họp mời các tu sĩ Toái Niết. Người vào phòng không che giấu tướng mạo; bên dưới có thể nhìn thấy đài đấu thú, còn trong phòng diễn ra đặt cược và giao dịch bảo vật.","theLucLienQuan":[],"nguon":["@c1102"]},{"id":"vu-tien-gioi","name":"Vũ Tiên giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Địa điểm được nhắc trong hồi tưởng về lần đầu Vương Lâm thi triển Dịch Linh Ấn khi giao đấu với Hồng Điệp.","detail":"Vũ Tiên giới là nơi Vương Lâm từng lần đầu thi triển Dịch Linh Ấn trong trận đấu với thiên kiêu Hồng Điệp; sự kiện này được hắn hồi tưởng trước khi hợp nhất toàn bộ kinh nghiệm thành một chưởng Dịch Linh Ấn ở Bồng Lai.","theLucLienQuan":[],"nguon":["@c1104"]},{"id":"lanh-tho-yeu-linh","name":"Lãnh thổ Yêu Linh","cn":"","capDo":"vuc","parentId":null,"blurb":"Địa điểm được nhắc trong hồi tưởng về các lần Vương Lâm từng thi triển Dịch Linh Ấn.","detail":"Lãnh thổ Yêu Linh được nhắc là nơi Vương Lâm từng thi triển Dịch Linh Ấn, khiến Yêu tướng Mạc Lực Hải khiếp sợ; cũng gắn với lần Dịch Linh Ấn phá tầng tám Tiên Đế động phủ khiến Lăng Thiên Hậu chấn động.","theLucLienQuan":[],"nguon":["@c1104"]},{"id":"tien-de-dong-phu","name":"Tiên Đế động phủ","cn":"","capDo":"khac","parentId":"lanh-tho-yeu-linh","blurb":"Động phủ được nhắc trong hồi tưởng về một lần Dịch Linh Ấn phá tầng tám, làm Lăng Thiên Hậu chấn động.","detail":"Tiên Đế động phủ nằm trong mạch hồi tưởng của Vương Lâm về Dịch Linh Ấn: thần thông này từng phá tầng tám của động phủ, tạo ra chấn động khiến Lăng Thiên Hậu sợ hãi.","theLucLienQuan":[],"nguon":["@c1104"]},{"id":"man-hoang-dai-luc-tinh-vuc-cap-sau","name":"Man Hoang đại lục tinh vực cấp sáu","cn":"","capDo":"vuc","parentId":null,"blurb":"Man Hoang đại lục tinh vực cấp sáu là nơi Đỗ Đức từng đoạt được lông vũ Chu Tước. Vùng này có mãnh thú am hiểu thần thông hệ hỏa và tồn tại mãnh thú cấp mười một.","detail":"Theo lời Đỗ Đức, Man Hoang đại lục này thuộc tinh vực cấp sáu, rất nguy hiểm vì mãnh thú nơi đó đều am hiểu thần thông hệ hỏa. Đây là manh mối quan trọng cho việc Vương Lâm tìm thêm lông vũ Chu Tước để hướng tới thức tỉnh lần thứ ba.","theLucLienQuan":["Đỗ Đức","Vương Lâm"],"nguon":["@c1105"]},{"id":"noi-bi-an-thuong-tung-tu","name":"Nơi bí ẩn Thương Tùng Tử","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi bí ẩn Thương Tùng Tử là địa điểm lão đã chuẩn bị suốt ngàn năm để tiến vào. Lão tin nếu vào được nơi này, tu vi sẽ tăng mạnh.","detail":"Thương Tùng Tử đưa ngọc giản liên quan đến địa điểm này cho Vương Lâm và đề nghị hợp tác. Vị trí cụ thể chưa lộ, nhưng nơi này đủ quan trọng để lão trả thù lao hai vạn nguyên tinh và bỏ qua nghi vấn về thân phận Vương Lâm.","theLucLienQuan":["Thương Tùng Tử","Vương Lâm"],"nguon":["@c1105"]},{"id":"quang-truong-trung-tam-chu-thanh-bong-lai","name":"Quảng trường trung tâm chủ thành Bồng Lai","cn":"","capDo":"khac","parentId":"bong-lai-dai-luc","blurb":"Quảng trường trung tâm trong chủ thành Bồng Lai, nơi Bảo Ngọc Tông tổ chức buổi đấu giá sau khi khu chợ được khôi phục.","detail":"Đấu giá diễn ra tại quảng trường chu vi nghìn trượng. Khi mở màn, mười sáu tấm bia đá khổng lồ cao trăm trượng, bốn mươi bia đá nhỏ hơn và hàng trăm bia đá khác trồi lên, tạo thành vòng tròn đại trận cho các tu sĩ tham gia đấu giá.","theLucLienQuan":["Bảo Ngọc Tông"],"nguon":["@c1106"]},{"id":"tinh-vuc-cap-chin","name":"Tinh vực cấp chín","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp chín được Trần Thiên Quân nhắc tới như nơi phát ra lời kêu gọi khiến hắn phải nhanh chóng quay về.","detail":"Trong lúc tham gia nhóm của Thương Tùng Tử, Trần Thiên Quân nói mình bị tinh vực cấp chín kêu gọi, phải sớm quay về đi cùng đồng môn. Chương chưa nói rõ vị trí hay thế lực cụ thể của tinh vực này.","theLucLienQuan":["Dịch Thú Tông"],"nguon":["@c1109"]},{"id":"vet-nut-bay-mau","name":"Vết nứt bảy màu","cn":"","capDo":"khac","parentId":"van-hai-tinh-vuc","blurb":"Vết nứt nhỏ nằm dưới vị trí Man Hoang đại lục che giấu, tỏa hào quang bảy màu và dẫn đến một kho tàng chưa rõ.","detail":"Thương Tùng Tử phát hiện vết nứt này từ năm xưa khi nó mới xuất hiện, sau đó kéo Man Hoang đại lục tới che phủ. Vết nứt không ổn định, nếu ít người vào sẽ thu nhỏ khó quay về, nên Thương Tùng Tử dùng cả đại lục đâm vào để cưỡng ép mở rộng trước khi dẫn đoàn tiến vào.","theLucLienQuan":[],"nguon":["@c1110"]},{"id":"te-dan-trong-the-gioi-bay-mau","name":"Tế đàn trong thế giới bảy màu","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Địa điểm nhóm người xuất hiện sau khi xuyên qua vết nứt bảy màu.","detail":"Tế đàn nằm trong phạm vi khoảng trăm trượng của thế giới bảy màu, là nơi mọi người phát hiện Vân Hồn Tử không được truyền tống tới cùng đội và nổ ra tranh cãi về nguyên nhân mất tích.","theLucLienQuan":[],"nguon":["@c1111"]},{"id":"son-coc-sau-trong-the-gioi-bay-mau","name":"Sơn cốc sâu trong thế giới bảy màu","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Nơi Vân Hồn Tử bị truyền tống lệch tới sau khi bị Vương Lâm tập kích.","detail":"Sơn cốc bị sương mù dày đặc bao phủ, bên trong có tiếng gầm rống và mùi máu tanh. Vân Hồn Tử mất tay phải, tâm thần kinh hoàng khi nhận ra mình rơi vào nơi nguy hiểm này.","theLucLienQuan":[],"nguon":["@c1111"]},{"id":"binh-nguyen-phia-truoc-te-dan","name":"Bình nguyên phía trước tế đàn","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Khu bình nguyên nằm sau tế đàn trên lộ tuyến Thương Tùng Tử dẫn đoàn người đi qua.","detail":"Sau khi rời tế đàn trong thế giới bảy màu, đoàn người đi qua bình nguyên này rồi tiếp tục tiến vào vùng núi sâu và sương mù nguy hiểm hơn.","theLucLienQuan":[],"nguon":["@c1112"]},{"id":"nui-sau-bi-suong-mu-bao-phu","name":"Núi sâu bị sương mù bao phủ","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Khu núi sâu trong thế giới bảy màu, nơi nguy hiểm ngày càng rõ và sương mù tồn tại độc lập giữa các dãy núi trụi lủi.","detail":"Đoàn người tiến qua khu vực núi sâu bị sương mù bao phủ sau bình nguyên. Tại đây Trần Thiên Quân phát hiện dấu vết động phủ, còn Thương Tùng Tử nhắc tới mãnh thú cấp mười hai từng thủ hộ nơi đó.","theLucLienQuan":[],"nguon":["@c1112"]},{"id":"dong-phu-trong-ngon-nui","name":"Động phủ trong ngọn núi","cn":"","capDo":"khac","parentId":"nui-sau-bi-suong-mu-bao-phu","blurb":"Động phủ nhân tạo trong núi sâu của thế giới bảy màu, được Trần Thiên Quân phát hiện trên đường đi.","detail":"Thương Tùng Tử xác nhận đây là một tòa động phủ từng có mãnh thú cấp mười hai thủ hộ. Lão từng dụ mãnh thú rời đi để vào trong và có thu hoạch.","theLucLienQuan":[],"nguon":["@c1112"]},{"id":"con-duong-hep-co-hoi-dan","name":"Con đường hẹp có Hồi đan","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Lối đi âm u giữa núi trong thế giới bảy màu, bị sương mù chắn và có nhiều hài cốt cùng Hồi đan.","detail":"Đây là nơi viên Hồi đan không hoàn chỉnh nằm bên hài cốt và tỏa mùi thuốc quỷ dị. Giao Long hóa sương cấp mười hai canh giữ khu vực này, khiến đoàn người phải phân chia lợi ích rồi hợp lực vây công.","theLucLienQuan":[],"nguon":["@c1112"]},{"id":"day-nui-hai-ben-con-duong-hep","name":"Dãy núi hai bên con đường hẹp","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Địa hình núi đá bao quanh con đường hẹp trong thế giới bảy màu, nơi chịu chấn động dữ dội khi Giao Long bị quật xuống.","detail":"Dãy núi hai bên con đường hẹp bị tiếng gầm và cú rơi của Giao Long hóa sương cấp mười hai làm rung chuyển, đá núi sụp rơi liên tục trong trận chiến của nhóm Vương Lâm.","theLucLienQuan":[],"nguon":["@c1113"]},{"id":"vi-tri-giao-tiep-ngoai-trong-the-gioi-bay-mau","name":"Vị trí giao tiếp giữa bên ngoài và bên trong thế giới bảy màu","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Khu vực ranh giới giữa phần ngoài và phần trong của thế giới bảy màu. Thương Tùng Tử nói động phủ của Tư Mã Mặc nằm tại đây và dùng thông tin này để thuyết phục nhóm tiếp tục đi.","detail":"Đây là mục tiêu tiếp theo mà Thương Tùng Tử tiết lộ sau biến cố Mê Thất Giả. Khu vực này được gắn với động phủ Tư Mã Mặc, đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, nơi có thể còn đan dược hoặc vật lưu lại.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1114"]},{"id":"dong-phu-tu-ma-mac","name":"Động phủ Tư Mã Mặc","cn":"","capDo":"khac","parentId":"vi-tri-giao-tiep-ngoai-trong-the-gioi-bay-mau","blurb":"Động phủ được Thương Tùng Tử xác định là thuộc về Tư Mã Mặc trong thế giới bảy màu. Nó có khả năng chứa đan dược hoặc nhiều vật còn lại từ người am hiểu luyện đan này.","detail":"Thương Tùng Tử dựa vào ngọc giản đoạt được trong thế giới bảy màu để khẳng định chủ nhân động phủ là Tư Mã Mặc. Lão dùng quyền chọn mười vật trong động phủ và lời hứa không tranh vật khác để khiến Vương Lâm tiếp tục đồng hành.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1114"]},{"id":"khe-nui-co-suong-mu","name":"Khe núi có sương mù","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Một vị trí trong thế giới bảy màu có sương mù và mãnh thú hóa sương hình rùa thích ăn tiên ngọc. Nhóm Thương Tùng Tử dùng nơi này để thu nguyên tinh cho Vương Lâm.","detail":"Thương Tùng Tử bóp vỡ tiên ngọc ném vào sương để dụ mãnh thú hóa sương, còn lão Bàng lao vào lấy nguyên tinh. Đợt đầu tại dạng vị trí này thu chưa tới ba ngàn nguyên tinh, sau nhiều điểm tương tự thì tổng gần hai vạn.","theLucLienQuan":[],"nguon":["@c1114"]},{"id":"con-duong-nho-hep-giua-hai-vach-nui","name":"Con đường nhỏ hẹp giữa hai vách núi","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Lộ tuyến hẹp đoàn người men theo nhiều ngày để tiến sâu trong thế giới bảy màu.","detail":"Con đường nằm giữa hai vách núi, trên đường đoàn người phải tránh mãnh thú hóa sương và các cấm chế tàn vỡ. Thương Tùng Tử dựa vào bản đồ để dẫn mọi người đi qua lộ tuyến này tới dãy núi cuối cùng.","theLucLienQuan":[],"nguon":["@c1115"]},{"id":"day-nui-cuoi-cung-vach-nui-duong-cut","name":"Dãy núi cuối cùng / vách núi đường cụt","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Chướng ngại chắn trước đoàn người ở cuối con đường hẹp trong thế giới bảy màu.","detail":"Theo ngọc giản bản đồ của Thương Tùng Tử, tại vách núi đường cụt này có cửa đường xuyên qua núi. Cửa đường bị Cửu Bộ Phong Tiên Trận phong ấn, buộc đoàn người phải tìm cách phá cấm.","theLucLienQuan":[],"nguon":["@c1115"]},{"id":"dinh-nui-co-bay-hung-thu-cap-muoi-hai","name":"Đỉnh núi có bảy hung thú cấp mười hai","cn":"","capDo":"khac","parentId":"day-nui-cuoi-cung-vach-nui-duong-cut","blurb":"Tuyến vượt núi phía trên bị Thương Tùng Tử xem là cực kỳ nguy hiểm.","detail":"Trên đỉnh núi có bảy hung thú cấp mười hai, từng khiến Thương Tùng Tử tổn thất lớn mà vẫn không thể vượt qua, nên đoàn người không chọn lối leo qua đỉnh.","theLucLienQuan":[],"nguon":["@c1115"]},{"id":"thach-dong-trong-nui","name":"Thạch động trong núi","cn":"","capDo":"khac","parentId":"day-nui-cuoi-cung-vach-nui-duong-cut","blurb":"Cửa động tối đen hiện ra sau khi Triệu lão bà kích động cấm chế trên vách núi.","detail":"Thạch động là lối xuyên núi được ngọc giản bản đồ chỉ ra. Khi cửa lộ ra, bên trong tối đen, ánh mắt nhìn vào như bị bóng tối thôn phệ, và lối vào bị Cửu Bộ Phong Tiên Trận phong ấn.","theLucLienQuan":[],"nguon":["@c1115"]},{"id":"day-nui-co-cuu-bo-phong-tien-tran","name":"Dãy núi có Cửu Bộ Phong Tiên Trận","cn":"","capDo":"khac","parentId":"nui-sau-bi-suong-mu-bao-phu","blurb":"Dãy núi có vách đá chứa Cửu Bộ Phong Tiên Trận, ngăn đường tiến vào khu vực bên trong.","detail":"Vách núi nơi đây có trận pháp khiến người vượt trận phải bước từng bước chịu uy áp tăng dần. Khi Vương Lâm bước tới bước thứ mười, trận pháp tan vỡ, cả dãy núi chấn động, đá trên vách tróc ra và đường đi bên trong mở ra.","theLucLienQuan":[],"nguon":["@c1116"]},{"id":"thong-dao-sau-khi-tran-vo","name":"Thông đạo sau khi trận vỡ","cn":"","capDo":"khac","parentId":"day-nui-co-cuu-bo-phong-tien-tran","blurb":"Con đường mở ra sau khi Cửu Bộ Phong Tiên Trận tan vỡ.","detail":"Thông đạo này giúp nhóm bốn người nhanh chóng tiến vào bên trong dãy núi, tránh khỏi mãnh thú hình ưng lao xuống từ sương mù trên đỉnh núi.","theLucLienQuan":[],"nguon":["@c1116"]},{"id":"vung-son-coc-ben-trong-day-nui","name":"Vùng sơn cốc bên trong dãy núi","cn":"","capDo":"khac","parentId":"day-nui-co-cuu-bo-phong-tien-tran","blurb":"Khu sơn cốc nằm sau dãy núi, được Thương Tùng Tử xem là phần bên trong thực sự.","detail":"Sau khi vượt thông đạo, nhóm người thấy trước mặt là những sơn cốc kéo dài, cỏ cây tràn ngập và hương thơm khiến tinh thần thoải mái. Từ đây Thương Tùng Tử dẫn mọi người tới nơi có động phủ của Tư Mã Mặc.","theLucLienQuan":[],"nguon":["@c1116"]},{"id":"dong-phu-bi-thuong-tung-tu-chon-tam","name":"Động phủ bị Thương Tùng Tử chọn tạm","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Động phủ nơi Thương Tùng Tử đưa nhóm vào, nhưng không phải động phủ thật của Tư Mã Mặc.","detail":"Qua ký ức lão Bàng, Vương Lâm xác định nơi này chỉ là động phủ Thương Tùng Tử tùy tiện tìm được để đánh lạc hướng, không phải mục tiêu thật sự liên quan Tư Mã Mặc.","theLucLienQuan":[],"nguon":["@c1117"]},{"id":"son-coc-truoc-day-nui","name":"Sơn cốc trước dãy núi","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Sơn cốc trước dãy núi là nơi Vương Lâm phát hiện cấm trận do lão bà áo xanh để lại. Tại đây hắn sửa mai phục thành phản bẫy bằng Phá Diệt Tâm Cấm.","detail":"Sơn cốc nằm gần dãy núi như bức tường chắn trong thế giới bảy màu. Mặt cỏ nơi đây hiện đồ án Mai Hoa Thập Bát Cấm khi Vương Lâm dùng cấm chế dò xét, đồng thời ẩn tầng hút sinh cơ có nét Sinh Tử Cấm; Vương Lâm thêm cấm chế của mình vào để tạo phản bẫy.","theLucLienQuan":[],"nguon":["@c1118"]},{"id":"day-nui-nhu-tuong-thanh","name":"Dãy núi như tường thành","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Dãy núi như tường thành ngăn cách vùng cỏ xanh bên ngoài với vùng sương mù đen bên trong. Vương Lâm vượt lên đỉnh cao nhất rồi phát hiện phương hướng của Thương Tùng Tử.","detail":"Dãy núi hiện ra như bức tường chắn lớn trong thế giới bảy màu. Sau khi vượt sơn cốc, Vương Lâm leo lên đỉnh núi cao nhất, nhìn thấy phía trong là biển sương mù đen dày đặc và cảm nhận được Thương Tùng Tử ở sâu bên trong.","theLucLienQuan":[],"nguon":["@c1118"]},{"id":"vung-suong-mu-den-trong-day-nui","name":"Vùng sương mù đen trong dãy núi","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Vùng sương mù đen trong dãy núi là khu vực Thương Tùng Tử và lão bà áo xanh thăm dò. Nơi đây có tượng đá nam tử dấu ấn tia chớp, âm thanh Minh Chí Giả và hư ảnh quỷ dị.","detail":"Phía sau dãy núi là vùng sương mù dày đặc như đại dương đen. Thương Tùng Tử mặc Thần Ma Giáp đi rất cẩn thận cùng lão bà áo xanh, gặp tượng đá cao gần trăm trượng và chứng kiến âm thanh, hư ảnh Minh Chí Giả xuyên qua người.","theLucLienQuan":[],"nguon":["@c1118"]},{"id":"suong-mu-quanh-vung-phong-an","name":"Sương mù quanh vùng phong ấn","cn":"","capDo":"khac","parentId":"vung-suong-mu-den-trong-day-nui","blurb":"Sương mù quanh vùng phong ấn là khu vực Thương Tùng Tử và lão bà áo xanh đi suốt nhiều ngày trước khi tới ngọn núi nhỏ.","detail":"Trong sương mù có âm thanh quỷ dị ảnh hưởng tâm thần, khiến người đi vào phải vất vả chống đỡ. Càng tiến sâu, âm thanh càng rõ và áp lực càng lớn.","theLucLienQuan":[],"nguon":["@c1119"]},{"id":"ngon-nui-nho-trong-suong-mu","name":"Ngọn núi nhỏ trong sương mù","cn":"","capDo":"khac","parentId":"suong-mu-quanh-vung-phong-an","blurb":"Ngọn núi nhỏ trong sương mù cao khoảng ngàn trượng, bị vầng sáng đen của Tuế Nguyệt Cấm bao bọc.","detail":"Thương Tùng Tử và lão bà áo xanh phát hiện ngọn núi này sau nhiều ngày tiến sâu trong sương mù. Màn cấm chế màu đen quanh núi ngăn người ngoài tiến vào và chỉ bị mở lỗ hổng sau khi nhiều bảo vật bị tự hủy.","theLucLienQuan":[],"nguon":["@c1119"]},{"id":"vung-dat-phong-an-ben-trong-cam-che","name":"Vùng đất phong ấn bên trong cấm chế","cn":"","capDo":"khac","parentId":"ngon-nui-nho-trong-suong-mu","blurb":"Vùng đất phong ấn bên trong cấm chế là nơi Thương Tùng Tử muốn tiến vào vì Đạo Kinh.","detail":"Thương Tùng Tử nói bên trong có nhiều linh hồn mãnh thú, nhưng mục tiêu thật của lão là Đạo Kinh. Lão và cô gái áo xanh tiến vào trước, sau đó Vương Lâm bố trí cấm chế bên ngoài rồi mới theo vào.","theLucLienQuan":[],"nguon":["@c1119"]},{"id":"khe-nut-tren-tam-man-tue-nguyet-cam","name":"Khe nứt trên tấm màn Tuế Nguyệt Cấm","cn":"","capDo":"khac","parentId":"vung-dat-phong-an-ben-trong-cam-che","blurb":"Lối vào tạm thời trên tấm màn Tuế Nguyệt Cấm. Khe nứt đang nhanh chóng khép lại, khiến thời gian ra vào khu vực bên trong trở nên gấp gáp.","detail":"Khe nứt là cửa mở trên phong ấn Tuế Nguyệt Cấm dẫn tới ngọn núi nhỏ bên trong. Nếu nó khôi phục hoàn toàn, muốn phá mở phải dùng rất nhiều bảo vật.","theLucLienQuan":[],"nguon":["@c1120"]},{"id":"ngon-nui-nho-trong-khe-nut","name":"Ngọn núi nhỏ trong khe nứt","cn":"","capDo":"khac","parentId":"khe-nut-tren-tam-man-tue-nguyet-cam","blurb":"Ngọn núi nhỏ hiện ra bên trong khe nứt Tuế Nguyệt Cấm. Nơi đây có cửa đá phong ấn thú hồn ở lưng chừng núi và đỉnh núi dùng để mở cầu vồng bảy màu.","detail":"Thương Tùng Tử dẫn cô gái áo xanh tới ngọn núi này, mở cửa động phủ thú hồn ở sườn núi rồi một mình lên đỉnh núi mở lối vào không gian tấm bia bảy màu.","theLucLienQuan":[],"nguon":["@c1120"]},{"id":"dong-phu-phong-an-thu-hon","name":"Động phủ phong ấn thú hồn","cn":"","capDo":"khac","parentId":"ngon-nui-nho-trong-khe-nut","blurb":"Động phủ sau cửa đá khắc đồ đằng tia chớp ở lưng chừng ngọn núi. Bên trong vang ra tiếng thú hồn gào thét xuyên thấu linh hồn.","detail":"Thương Tùng Tử dùng con lắc màu trắng hình tia chớp mở cửa động phủ rồi dụ Triệu đạo hữu vào trong lấy thú hồn. Sau đó lão khép cửa đá lại, khiến bên trong truyền ra tiếng gầm giận dữ và va chạm.","theLucLienQuan":[],"nguon":["@c1120"]},{"id":"khong-gian-tam-bia-bay-mau","name":"Không gian tấm bia bảy màu","cn":"","capDo":"gioi-nho","parentId":"ngon-nui-nho-trong-khe-nut","blurb":"Không gian nằm sau vòng xoáy ở cuối cầu vồng bảy màu trên đỉnh núi. Nơi đây có tấm bia cao vạn trượng, hài cốt đen khắc Đạo Kinh và bình ngọc dưới trận pháp.","detail":"Thương Tùng Tử vào không gian này sau khi đọc âm thanh kỳ dị trên đỉnh núi. Uy áp từ tấm bia khiến lão phải quỳ lạy; dưới bia là nửa bộ hài cốt bị đinh bảy màu đóng giữ, văn tự Đạo Kinh phủ trên xương và bình ngọc nằm dưới trận pháp ngục tù.","theLucLienQuan":[],"nguon":["@c1120"]},{"id":"tam-man-cam-che","name":"Tấm màn cấm chế","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Màn chắn cấm chế có khe nứt đang khép lại trong thế giới bảy màu.","detail":"Tấm màn cấm chế là ranh giới mà Thương Tùng Tử và Vương Lâm tìm cách vượt qua. Khe nứt trên màn đang khép lại, sau khi Vương Lâm lao ra hắn còn đánh cấm chế vào đó để khiến tốc độ khép nhanh hơn.","theLucLienQuan":[],"nguon":["@c1121"]},{"id":"suong-mu-ben-ngoai","name":"Sương mù bên ngoài","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Khu vực bên ngoài tấm màn nơi Vương Lâm lao qua sau khi đoạt bình ngọc.","detail":"Sau khi đoạt bình ngọc, Vương Lâm xuyên qua sương mù bên ngoài; nơi này có âm thanh quỷ dị và nhiều bóng người hoặc hư ảnh lướt qua, đồng thời Minh Chí Giả bị tiếng nổ hấp dẫn kéo tới.","theLucLienQuan":["Minh Chí Giả"],"nguon":["@c1121"]},{"id":"son-coc-dat-cam-che","name":"Sơn cốc đặt cấm chế","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Sơn cốc nơi Vương Lâm bố trí cấm chế từ trước để phản kích lão phụ nhân áo xanh.","detail":"Khi bị truy kích trong thế giới bảy màu, Vương Lâm dẫn lão phụ nhân áo xanh tới sơn cốc này. Tại đây hắn điều khiển ngược vòng xoáy khói đen và mở hàng vạn cấm chế để vây bà ta vào thế sinh tử.","theLucLienQuan":[],"nguon":["@c1122"]},{"id":"son-coc-trung-tam-the-gioi-bay-mau","name":"Sơn cốc trung tâm thế giới bảy màu","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Vị trí trung tâm thật sự của thế giới bảy màu, một sơn cốc sâu hơn bao phủ trong sương mù, không phải nơi Thương Tùng Tử đang chữa thương.","detail":"Thương Tùng Tử tiết lộ vị trí trung tâm thật sự của thế giới bảy màu là một sơn cốc được bao phủ trong sương mù, nằm sâu hơn nơi lão đang ngồi trên ký hiệu tia chớp mi tâm bức tượng đá.","theLucLienQuan":[],"nguon":["@c1124"]},{"id":"day-nui-manh-thu-hoa-suong","name":"Dãy núi mãnh thú hóa sương","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Dãy núi non san sát bên ngoài thế giới bảy màu, đỉnh núi có sương mù dày đặc ẩn chứa mãnh thú hình ưng cấp 12.","detail":"Khu vực núi non nằm phía ngoài thế giới bảy màu, đỉnh núi phủ sương mù dày đặc với nhiều mãnh thú hóa sương hình ưng cấp 12 ẩn náu. Vương Lâm đi theo con đường cũ ra đây để lợi dụng đòn tấn công của mãnh thú ép cây đinh bảy màu ra khỏi thân thể.","theLucLienQuan":[],"nguon":["@c1125"]},{"id":"duong-ngam-trong-nui-bay-mau","name":"Đường ngầm trong núi","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Con đường ngầm bên trong ngọn núi nơi Vương Lâm trốn vào dưỡng thương hai ngày sau khi đoạt cây đinh bảy màu.","detail":"Nằm trong ngọn núi thuộc thế giới bảy màu. Ba mãnh thú hình ưng không dám đuổi theo vào bên trong. Vương Lâm ẩn trong đường ngầm bố trí cấm chế phòng thủ, dùng đan dược và lực Cổ Thần dưỡng thương hai ngày khôi phục đỉnh phong.","theLucLienQuan":[],"nguon":["@c1126"]},{"id":"vung-son-coc-day-dac","name":"Vùng sơn cốc dày đặc","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Khu vực rộng lớn chứa nhiều sơn cốc mà Vương Lâm xuyên qua trên đường đến động phủ Tư Mã Mặc.","detail":"Phần lớn cấm chế trong khu vực này đã tan vỡ, các động phủ khác đều trống trơn. Động phủ Tư Mã Mặc nằm trong một sơn cốc bình thường giữa khu vực này.","theLucLienQuan":[],"nguon":["@c1126"]},{"id":"con-nhai-tinh-vuc","name":"Côn Nhai","cn":"昆崖","capDo":"tinh-cau","parentId":null,"blurb":"Tinh vực được nhắc cùng Vân Hải, La Thiên, Triệu Hà trong di ngôn Tư Mã Mặc.","detail":"Được Tư Mã Mặc nhắc tên khi mô tả bí mật khổng lồ khiến tu chân giới khiếp sợ.","theLucLienQuan":["Côn Nhai"],"nguon":["@c1126"]},{"id":"dong-phu-thu-nhat-vach-da","name":"Động phủ thứ nhất trên vách đá","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ đầu tiên trong chín động phủ trên vách đá sơn cốc thế giới bảy màu, rộng khoảng mười trượng, chứa mười hạt châu nổi lơ lửng trong vùng sáng màu tro.","detail":"Vương Lâm bay lên mở động phủ thứ nhất trên vách đá. Bên trong rộng khoảng mười trượng, có mười hạt châu to bằng nắm tay trẻ sơ sinh nổi lơ lửng trong vùng sáng màu tro, trên dưới có ký hiệu mờ nhạt lóe sáng xám. Đây là loại hạt châu Thương Tùng Tử dùng triệu hoán thần thông Nghịch Hành Giả, trên có chữ Thiên Nghịch.","theLucLienQuan":["Phá Thiên Tông"],"nguon":["@c1127"]},{"id":"vi-tri-sau-nhat-the-gioi-bay-mau","name":"Vị trí sâu nhất trong thế giới bảy màu","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Nơi sâu nhất trong thế giới bảy màu, nơi Tứ sư thúc (Nghịch Hành Giả đầu tiên) ở, có cây đinh bảy màu, Tư Mã Đặc vào lần thứ tư bị thương.","detail":"Vị trí sâu nhất trong thế giới bảy màu, phát ra âm thanh kêu gọi khiến sư thúc của Tư Mã Đặc đi vào (năm thứ 11). Tứ sư thúc trở thành Nghịch Hành Giả tại đây. Tư Mã Đặc lần thứ tư tiến vào cứu Tứ sư thúc nhưng thất bại, bị cây đinh bảy màu đâm vào cơ thể.","theLucLienQuan":[],"nguon":["@c1127"]},{"id":"dong-phu-thu-hai-lo-luyen-dan","name":"Động phủ thứ hai (lò luyện đan)","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Động phủ thứ hai trong thế giới bảy màu, chứa lò luyện đan khổng lồ và dược liệu số lượng khổng lồ.","detail":"Lò luyện đan chiếm hơn nửa động phủ, dược thảo khô héo chất đống cùng túi trữ vật đầy dược liệu. Vương Lâm dùng lò để luyện hóa lại đan cấp mười một.","theLucLienQuan":[],"nguon":["@c1128"]},{"id":"dong-phu-thu-ba-dan-duoc","name":"Động phủ thứ ba (đan dược)","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Động phủ thứ ba trong thế giới bảy màu, nơi Tư Mã Mặc để lại ba bình đan dược quý được trận pháp bảo vệ.","detail":"Cửa động có cấm chế riêng (không phải Tuế Nguyệt Cấm). Bên trong có trận pháp hình tròn dùng nguyên tinh vận chuyển giữ ba bình đan dược lơ lửng, vừa chống hao mòn năm tháng vừa phòng hộ: cưỡng ép mở thì đan tan vỡ. Vương Lâm dùng trận pháp hình thoi chuyển hướng khí tức hủy diệt để đoạt ba bình an toàn.","theLucLienQuan":[],"nguon":["@c1128"]},{"id":"te-dan-trong-suong-mu","name":"Tế đàn trong sương mù","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Tế đàn phủ sương nằm rất sâu trong thế giới bảy màu, nơi nhóm người mang ký hiệu mi tâm xuất hiện.","detail":"Nằm rất sâu trong thế giới bảy màu, cách xa vị trí Thương Tùng Tử. Tế đàn lóe hào quang xua tan sương mù, làm xuất hiện nhóm ba người y phục khác tu sĩ Vân Hải mang ký hiệu tia chớp, trăng lưỡi liềm và ngọn lửa đồ đằng trên mi tâm.","theLucLienQuan":[],"nguon":["@c1128"]},{"id":"hai-ngon-nui-bi-mat-suong-mu","name":"Hai ngọn núi bí mật trong sương mù","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Hai ngọn núi ẩn trong sương mù dày đặc dãy núi vòng cung, bị Tuế Nguyệt Cấm bao quanh. Ngọn thứ nhất chứa bia đá không chữ giống pháp khí, ngọn thứ hai chứa kho thú hồn phong ấn, thiếu nữ giống lão bà áo xanh, và không gian ẩn giấu có nửa bộ hài cốt bị đinh bảy màu ghim.","detail":"Nằm sâu trong sương mù dày đặc của dãy núi hình vòng cung trong thế giới bảy màu, bị Tuế Nguyệt Cấm bao quanh. Ngọn núi thứ nhất chỉ có một tấm bia đá không chữ toát khí tức tang thương giống pháp khí. Ngọn núi thứ hai có tượng đá khổng lồ bên ngoài, cửa đá cực lớn với ký hiệu hình tia chớp, bên trong chứa nhiều thú hồn phong ấn từ cấp bảy đến cấp mười ba, một thiếu nữ giống lão bà áo xanh đang thổ nạp, và không gian ẩn giấu chứa nửa bộ hài cốt bị hai cây đinh bảy màu ghim với chữ viết dâng tặng Tu Chân Hành.","theLucLienQuan":["Thiên Lôi Tộc"],"nguon":["@c1130"]},{"id":"vung-sau-the-gioi-bay-mau","name":"Vùng sâu bên trong thế giới bảy màu","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Khu vực phía sau sương mù dày đặc hơn trong thế giới bảy màu, nơi ba thanh niên ba tộc (Thiên Lôi, Hỏa Tước, trăng lưỡi liềm) đang thám hiểm. Có khí tức tổ tiên Thiên Lôi Tộc và Hỏa Tước Tộc.","detail":"Vùng sâu nhất mà tâm thần Vương Lâm lần đầu tiên xuyên tới, nằm phía sau sương mù dày đặc. Ba thanh niên ba bộ tộc (Thiên Lôi Tộc, Hỏa Tước Tộc, trăng lưỡi liềm) đang thám hiểm nơi đây. Cả thanh niên Thiên Lôi Tộc lẫn Hỏa Tước Tộc đều cảm nhận khí tức tổ tiên bộ tộc mình tại khu vực này.","theLucLienQuan":["Thiên Lôi Tộc","Hỏa Tước Tộc"],"nguon":["@c1130"]},{"id":"ngon-nui-cao-the-gioi-bay-mau","name":"Ngọn núi cao (thế giới bảy màu)","cn":"","capDo":"khac","parentId":"vung-sau-the-gioi-bay-mau","blurb":"Ngọn núi rất cao nằm trong thế giới bảy màu, bốn phía không có cấm chế, sương mù phải tản ra xa không dám tới gần. Bên trong có lão già tóc trắng Toái Niết hậu kỳ trấn thủ, đang bảo vệ thứ bí mật.","detail":"Ngọn núi nổi bật nhất trong thế giới bảy màu, sương mù né tránh không dám tiếp cận. Không có cấm chế nào xung quanh. Lão già tóc trắng tu vi Toái Niết hậu kỳ ẩn bên trong, phóng thần thức tấn công kẻ lạ xâm nhập. Vương Lâm nhận định lão đang bảo vệ thứ gì đó trong ngọn núi.","theLucLienQuan":[],"nguon":["@c1131"]},{"id":"cung-dien-cam-dia-thai-co-tinh-vuc","name":"Cung điện bí ẩn (cấm địa Thái Cổ tinh vực)","cn":"","capDo":"khac","parentId":"ngoai-gioi","blurb":"Tòa cung điện không người, không sinh cơ, tràn ngập luồng sáng bảy màu, nằm trong cấm địa ngoài tinh không Thái Cổ tinh vực.","detail":"Chứa nhiều khối ngọc giản khắc tên các tu sĩ (Thanh Thủy, Thiên Vận Tử, Trọng Huyền Tử, Thủy Đạo Tử, Tư Mã Mặc, Thương Tùng Tử). Có giọng nói bí ẩn thì thào, sở hữu sức mạnh nghịch chuyển thời gian ngưng tụ lại ngọc giản đã vỡ. Khi Thương Tùng Tử chết, ngọc giản tái ngưng tụ đổi tên thành Vương Lâm.","theLucLienQuan":[],"nguon":["@c1132"]},{"id":"dong-phu-thu-tu","name":"Động phủ thứ tư","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ thứ tư trong chín động phủ ở sơn cốc thế giới bảy màu, bên trong trống rỗng.","detail":"Vương Lâm mở ra và phát hiện bên trong trống rỗng, không có gì đặc biệt.","theLucLienQuan":[],"nguon":["@c1133"]},{"id":"dong-phu-thu-sau","name":"Động phủ thứ sáu","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ thứ sáu trong sơn cốc, chứa ba Minh Chí giả bị cấm chế phong ấn và ngọc giản Tuế Nguyệt Cấm.","detail":"Bên trong có ba Minh Chí giả chỉ còn nguyên thần bay bổng lẩm bẩm, bị cấm chế phong ấn. Trung tâm có ngọc giản chứa Tuế Nguyệt Cấm do Tư Mã Đặc để lại cho đồng môn tự giải phong ấn khi thức tỉnh.","theLucLienQuan":[],"nguon":["@c1133"]},{"id":"dong-phu-thu-bay","name":"Động phủ thứ bảy","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ thứ bảy trong sơn cốc, chứa lão già tóc hoa râm bị phong ấn cấm chế dày đặc, nghi là Nghịch Hành Giả.","detail":"Bên trong có lão già tóc hoa râm bị phong ấn cấm chế dày đặc. Khi thấy Vương Lâm, lão phát điên cuồng gào thét lao ra tấn công vách đá nhưng thần thông bị cấm chế hút sạch, cuối cùng mệt mỏi lui về ngồi tĩnh tọa. Vương Lâm nghi đây là Nghịch Hành Giả.","theLucLienQuan":[],"nguon":["@c1133"]},{"id":"dong-phu-thu-tam","name":"Động phủ thứ tám","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ thứ tám trong sơn cốc, chứa nửa bộ hài cốt phần dưới bị trận pháp phong ấn.","detail":"Cấm chế bình thường, Vương Lâm dễ dàng mở ra. Bên trong có nửa bộ hài cốt phần dưới, kinh văn đen trên khung xương, bị trận pháp phong ấn. Hài cốt tỏa lực hút khổng bố muốn hấp thu tâm thần. Trên đùi phải có vết nứt rất sâu — Vương Lâm dung nhập tâm thần qua vết nứt này để cảm ngộ.","theLucLienQuan":[],"nguon":["@c1133"]},{"id":"dong-phu-thu-chin","name":"Động phủ thứ chín","cn":"","capDo":"khac","parentId":"son-coc-trung-tam-the-gioi-bay-mau","blurb":"Động phủ cuối cùng trong sơn cốc thế giới bảy màu, cấm chế quá mạnh Vương Lâm không thể phá, bên trong tràn đầy sương mù.","detail":"Vương Lâm không mở được vì cấm chế quá mạnh, chỉ thấy bên trong tràn đầy sương mù.","theLucLienQuan":[],"nguon":["@c1134"]},{"id":"tinh-khong-ao-canh-mat-tuong-da","name":"Tinh không trong ảo cảnh mắt tượng đá","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng tinh không hiện ra khi hai mắt tượng đá tổ tiên Thiểm Lôi tộc bùng hào quang, chứa trận pháp lớn như tinh vực giam cầm Luyện Khí Sĩ và Tiên nhân.","detail":"Xuất hiện dưới dạng ảo cảnh trong mắt tượng đá màu đen sau khi Vương Lâm đánh ký hiệu tia chớp vào mi tâm. Bên trong có trận pháp khổng lồ phong tỏa bốn phía lớn như một tinh vực, giam cầm rất nhiều Luyện Khí Sĩ và Tiên nhân tuyệt vọng. Bên ngoài trận pháp có vô số người kỳ dị không phải tu sĩ đứng chi chít với nụ cười chế giễu. Trong trận pháp có chín luồng hào quang tàn sát mọi người, bao gồm Khai Thiên Phủ và tia chớp.","theLucLienQuan":["Luyện Khí Sĩ","Thiểm Lôi tộc"],"nguon":["@c1135"]},{"id":"ngon-nui-tue-nguyet-cam","name":"Ngọn núi bao phủ Tuế Nguyệt Cấm","cn":"","capDo":"khac","parentId":"vung-sau-the-gioi-bay-mau","blurb":"Ngọn núi bị Tuế Nguyệt Cấm bao phủ, bên trong có động phủ và khe nứt không gian dẫn đến không gian kỳ dị chứa bia đá và hài cốt Chiến Tinh Dã.","detail":"Nơi trước đó Vương Lâm tranh đoạt bình ngọc với Thương Tùng Tử. Vết nứt trên cấm chế do Thương Tùng Tử và lão bà áo xanh phá vỡ, tuy đã khép lại nhưng chưa liền hẳn. Vương Lâm dùng Phá Diệt Cấm + Thủy Tinh Kiếm + Tam Xoa Kích xé toạc cấm chế tiến vào bên trong.","theLucLienQuan":[],"nguon":["@c1136"]},{"id":"khong-gian-ky-di-bia-da","name":"Không gian kỳ dị (chứa bia đá và hài cốt)","cn":"","capDo":"khac","parentId":"ngon-nui-tue-nguyet-cam","blurb":"Không gian kỳ dị bên trong khe nứt, chứa tấm bia đá khổng lồ và nửa bộ hài cốt Chiến Tinh Dã bị đinh bảy màu ghim chặt.","detail":"Vương Lâm tiến vào qua khe nứt không gian trong động phủ giữa ngọn núi Tuế Nguyệt Cấm. Bên trong có tấm bia đá khổng lồ bao phủ khí tức tang thương, nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt trên bia đá, lưu chuyển hào quang tạo sức hấp dẫn khiến kẻ khác điên cuồng.","theLucLienQuan":[],"nguon":["@c1136"]},{"id":"dia-phuong-thiem-dien-toc","name":"Địa phương Thiểm Điện tộc","cn":"","capDo":"khac","parentId":"ngoai-gioi","blurb":"Vùng đất trong Thái Cổ tinh vực có hàng loạt sấm sét tồn tại vĩnh hằng và miếu thờ lôi quang, nơi cư trú của Thiểm Điện tộc.","detail":"Địa phương của Thiểm Điện tộc trong Thái Cổ tinh vực, có hàng loạt sấm sét tồn tại vĩnh hằng và miếu thờ lôi quang. Khi thanh niên ký hiệu tia chớp chết và Vương Lâm thu hồi lực sấm sét, sấm sét vĩnh hằng tiêu tán trong mười hơi thở rồi tái xuất, gây kinh hoàng cho toàn tộc.","theLucLienQuan":["Thiểm Điện tộc"],"nguon":["@c1138"]},{"id":"dia-phuong-hoa-tuoc-toc","name":"Địa phương Hỏa Tước tộc","cn":"","capDo":"khac","parentId":"ngoai-gioi","blurb":"Vùng đất trong Thái Cổ tinh vực bao phủ trong lửa, giống Chu Tước Thánh Tông, có nhiều miếu thờ tượng Nhạn Tước toàn thân đen.","detail":"Địa phương của Hỏa Tước tộc trong Thái Cổ tinh vực, bao phủ trong lửa, cảnh quan rất giống Chu Tước Thánh Tông. Có nhiều miếu thờ với tượng chim lửa toàn thân màu đen gọi là Nhạn Tước. Khi thanh niên ký hiệu ngọn lửa chết, ba pho tượng Nhạn Tước tan vỡ, ứng với truyền thuyết khi bọn họ sắp quay về.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1138"]},{"id":"cam-dia-nguyet-phe-toc","name":"Cấm địa Nguyệt Phệ tộc","cn":"","capDo":"khac","parentId":null,"blurb":"Cấm địa nằm phía bắc tinh vực Nguyệt Phệ tộc, chứa chín pho tượng Cổ Thần khổng lồ.","detail":"Không cho phép tộc nhân thường bước vào, canh giữ nghiêm ngặt. Bên trong cực kỳ lặng lẽ như tử vực. Chín lão già thiên tư cao nhất bộ tộc ngồi trên tượng cưỡng chế hấp thu lực lượng Cổ Thần. Khi quy ước Thái Cổ bị xóa, chín pho tượng đồng loạt nứt vỡ sụp đổ.","theLucLienQuan":["Nguyệt Phệ tộc"],"nguon":["@c1139"]},{"id":"cung-dien-bay-bong-thai-co-tinh-than","name":"Cung điện bay bổng trong tinh không Thái Cổ Tinh Thần","cn":"","capDo":"khac","parentId":null,"blurb":"Cung điện bay giữa tinh không mênh mông Thái Cổ Tinh Thần, đen tối, bên trong có ngọc giản trôi nổi chiếu sáng và cây nến.","detail":"Có ít nhất hai nhân vật bí ẩn ngồi bên trong quan sát sự kiện Chu Tước thức tỉnh. Bầu không khí cực kỳ âm u. Một người điểm ngón tay héo rũ lên nến lửa, người kia chất vấn bằng giọng lạnh như băng.","theLucLienQuan":[],"nguon":["@c1139"]},{"id":"tu-thanh-ton","name":"Tứ Thánh tồn","cn":"四圣存","capDo":"thanh","parentId":"van-hai-tinh-vuc","blurb":"Nơi cư ngụ của tộc nhân Chu Tước Thánh Tông trong Liên Minh tinh vực, xuất hiện hiện tượng cộng hưởng lửa khi Chu Tước thức tỉnh lần ba.","detail":"Tứ Thánh tồn nằm trong Liên Minh tinh vực, là nơi tộc nhân Chu Tước Thánh Tông cư ngụ. Khi Vương Lâm hoàn thành Chu Tước thức tỉnh lần ba tại thế giới bảy màu, toàn bộ tộc nhân tại đây đồng loạt mất kiểm soát ngọn lửa trong cơ thể — hiện tượng chưa từng có.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c1140"]},{"id":"dai-dien-thanh-long","name":"Đại điện Thanh Long","cn":"","capDo":"khac","parentId":"chu-tuoc-tinh","blurb":"Nơi Thanh Long Thánh Hoàng bế quan, bên trong có mật thất với tám sợi xích sắt ghim vách tường và bốn thanh Thái Cổ Tứ Thánh Khí trấn áp.","detail":"Nơi Thanh Long Thánh Hoàng bế quan một tháng. Mật thất bên trong có tám sợi xích sắt đen ghim vào bốn vách tường, bốn thanh Thái Cổ Tứ Thánh Khí bay bổng trấn áp. Bốn trưởng lão canh giữ bên ngoài đại điện.","theLucLienQuan":["Tứ Thánh Tông"],"nguon":["@c1141"]},{"id":"khe-nut-khong-gian-chu-tuoc-tinh","name":"Khe nứt không gian nối Chu Tước tinh","cn":"","capDo":"khac","parentId":"chu-tuoc-tinh","blurb":"Khe nứt không gian nơi Cổ Thần sắp thức tỉnh, trận pháp thái cổ dùng máu và ấn ký tứ tộc đã bố trí xong.","detail":"Khe nứt không gian nối với Chu Tước tinh, bên trong có Cổ Thần sắp thức tỉnh. Tứ Thánh Tông đã dùng máu và ấn ký tộc nhân tứ tộc bố trí trận pháp thái cổ để đối phó.","theLucLienQuan":["Tứ Thánh Tông"],"nguon":["@c1141"]},{"id":"cua-dong-nham-thach-the-gioi-bay-mau","name":"Cửa động nham thạch (thế giới bảy màu)","cn":"","capDo":"khac","parentId":"the-gioi-bay-mau","blurb":"Bên trong cửa động ở vị trí sâu nhất thế giới bảy màu, đầy nham thạch nóng chảy, khóa sắt treo hài cốt, ngọc giản phong ấn đạo niệm — nơi trung chuyển đạo niệm trước khi đưa vào tinh không bảy cây hoa.","detail":"Địa phương đầy nham thạch nóng chảy nằm bên trong cửa động ở vị trí sâu nhất thế giới bảy màu. Có nhiều khóa sắt treo hài cốt khô héo, ngọc giản lơ lửng phong ấn đạo niệm, ký hiệu khắc dưới đáy nham thạch hấp thu đạo niệm. Nham thạch xuyên qua động phủ tiến vào tinh không bảy cây hoa, là nơi trung chuyển đạo niệm từ bên ngoài vào hệ thống Loại Đạo.","theLucLienQuan":[],"nguon":["@c1146"]},{"id":"tinh-khong-bay-cay-hoa","name":"Tinh không bảy cây hoa","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng tinh không cực kỳ khổng lồ chứa nhiều tinh vực tạo thành đại trận, trung tâm có bảy cây hoa bảy màu, phía tây kết nối đại trận bao quanh Phong giới.","detail":"Vùng tinh không cực kỳ khổng lồ nằm bên kia nham thạch trong cửa động thế giới bảy màu. Bên trong có nhiều tinh vực tạo thành đại trận lớn bằng một Liên Minh tinh vực. Trung tâm có bảy cây hoa bảy màu cao khoảng trăm trượng, là nguồn sống cung cấp dưỡng chất cho toàn bộ tinh không. Phía tây có đại trận bao quanh Phong giới, hấp thu đạo niệm tu sĩ chết trên Phong giới làm dinh dưỡng nuôi bảy cây hoa. Tồn tại từ thượng cổ.","theLucLienQuan":[],"nguon":["@c1146"]},{"id":"vet-nut-chien-truong-yeu-tong","name":"Vết nứt chiến trường (Yêu Tông)","cn":"","capDo":"khac","parentId":null,"blurb":"Chiến trường vết nứt trong Yêu Tông (tinh vực cấp chín), nơi tu sĩ chiến đấu chống mãnh thú.","detail":"Vết nứt là chiến trường chính của Yêu Tông, nơi Lý Thiến Mai trải trăm năm chém giết mãnh thú. Tu sĩ các tông phái khác cũng tham chiến dưới sự chỉ huy của Yêu Tông.","theLucLienQuan":["Yêu Tông"],"nguon":["@c1147"]},{"id":"vung-hu-vo-ngoai-tu-dai-gioi","name":"Vùng hư vô ngoài Tứ Đại giới","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian hư vô nằm giữa Tứ Đại giới và Phong Giới đại trận, nơi Thác Sâm đối đầu với trận pháp phong tỏa.","detail":"Vùng hư vô nằm ở bên ngoài ranh giới Tứ Đại Tiên Giới, là nơi tồn tại Phong Giới đại trận ngăn cách Ngoại Giới và Thái Cổ Tinh Thần. Thác Sâm phá nứt tinh không Vân Hải để đến đây và tấn công trận pháp.","theLucLienQuan":[],"nguon":["@c1148"]},{"id":"noi-gioi","name":"Nội giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Khu vực bị trận pháp Phong giới phong tỏa, nơi Thác Sâm và bộ tộc Cổ Thần bị giam giữ.","detail":"Khu vực bị trận pháp Phong giới phong tỏa, trói buộc bộ tộc Cổ Thần của Thác Sâm. Thác Sâm phá trận pháp tạo khe nứt đầu tiên và xông ra ngoài đến Thái Cổ Tinh Thần.","theLucLienQuan":["Cổ Thần tộc"],"nguon":["@c1149"]},{"id":"tinh-vuc-tran-phap-hoa-bay-mau","name":"Tinh vực trận pháp (nơi trồng hoa bảy màu)","cn":"","capDo":"khac","parentId":null,"blurb":"Tinh vực do trận pháp mở ra, không thuộc Nội giới cũng không phải Ngoại giới. Bên trong có bảy cây hoa bảy màu do Chưởng Tôn bỏ tâm huyết nuôi trồng.","detail":"Tinh vực đặc biệt do trận pháp mở ra, nằm ngoài phạm trù Nội giới và Ngoại giới. Bên trong có bảy cây hoa bảy màu khác nhau, trong đó cây hoa đỏ thẫm đang kết Đạo quả. Sau khi Thiên Nghịch hấp thu sạch cây hoa đỏ, chỉ còn lại sáu cây cùng hạt châu Thiên Nghịch lơ lửng. Thiên Nghịch bùng sáng vạn trượng bao phủ cả tinh vực, triệu hoán cánh cửa hư ảo khổng lồ.","theLucLienQuan":[],"nguon":["@c1150"]},{"id":"canh-cua-hu-ao-khong-lo","name":"Cánh cửa hư ảo khổng lồ","cn":"","capDo":"khac","parentId":"tinh-vuc-tran-phap-hoa-bay-mau","blurb":"Cánh cửa hư ảo xuất hiện sau khi Thiên Nghịch bùng sáng, đủ lớn chống đỡ thiên địa, tỏa khí tức tang thương, đang khép kín hoàn toàn.","detail":"Xuất hiện trong tinh vực sau khi hạt châu Thiên Nghịch bùng ra hào quang chói mắt cao vạn trượng bao phủ cả tinh vực. Cánh cửa đủ lớn để chống đỡ thiên địa, tỏa ra khí tức tang thương, đang khép kín hoàn toàn không có bất kỳ khe hở nào. Chưa rõ dẫn đến đâu.","theLucLienQuan":[],"nguon":["@c1150"]},{"id":"that-thai-gioi","name":"Thất Thải Giới","cn":"七彩界","capDo":"gioi-nho","parentId":null,"blurb":"Nơi thân xác Vương Lâm nằm ngủ trăm năm phủ đầy bụi đất, tỉnh dậy và đột phá Tịnh Niết đại viên mãn tại đây.","detail":"Nơi thân xác Vương Lâm nằm tại chỗ sâu nhất chìm trong bóng tối, ngủ say trăm năm. Sau khi nguyên thần dung nhập thi thể, Vương Lâm tỉnh dậy và đột phá Tịnh Niết đại viên mãn tại đỉnh núi nơi đây.","theLucLienQuan":[],"nguon":["@c1151","@c1154"]},{"id":"lam-son","name":"Lam Sơn","capDo":"khac","parentId":"tinh-vuc-lam-ti-toc","blurb":"Ngọn núi quanh năm lam quang bao phủ, nằm trên một tinh cầu tầm thường trong tinh vực Lam Ti tộc. Trên đỉnh có nhà tranh đơn giản — nơi ở của Lam Mộng Đạo Tôn.","detail":"Lam Sơn nằm trong Thái Cổ Tinh Thần, thuộc tinh vực của bộ tộc Lam Ti. Trên đỉnh núi có nhà tranh đơn giản, là nơi cư ngụ của Lam Mộng Đạo Tôn — một trong Thái Cổ Ngũ Tôn.","theLucLienQuan":["Thái Cổ Tinh Thần Lam Ti Tộc"],"nguon":["@c1157"]},{"id":"tinh-vuc-lam-ti-toc","name":"Tinh vực Lam Ti tộc","capDo":"vuc","parentId":null,"blurb":"Tinh vực vô biên vô hạn do bộ tộc Lam Ti chiếm cứ trong Thái Cổ Tinh Thần.","detail":"Vùng tinh vực rộng lớn thuộc quyền kiểm soát của bộ tộc Lam Ti trong Thái Cổ Tinh Thần. Quy mô vô biên vô hạn.","theLucLienQuan":["Thái Cổ Tinh Thần Lam Ti Tộc"],"nguon":["@c1157"]},{"id":"ngu-giai-tinh-vuc","name":"Ngũ giai tinh vực","cn":"","capDo":"vuc","parentId":"van-hai-tinh","blurb":"Khu vực thuộc Vân Hải tinh vực, nơi Thiên Cương Tông tọa lạc và có đại lục hoang dã sâu nhất — nơi Vương Lâm xuất hiện trở lại.","detail":"Ngũ giai tinh vực là vùng thuộc Vân Hải tinh vực, nơi các phân tông ngũ giai như Thiên Cương Tông hoạt động. Sâu nhất trong vùng này có một đại lục hoang dã, nơi Vương Lâm vọt ra trở về.","theLucLienQuan":["Thiên Cương Tông","Ứng Thiên Tông"],"nguon":["@c1158"]},{"id":"thien-hai-dai-luc","name":"Thiên Hải đại lục","cn":"","capDo":"khac","parentId":"van-hai-tinh","blurb":"Nơi sinh của Chúc Duẫn Minh và La Tòng Cương.","detail":"Thiên Hải đại lục, nơi sinh của tông chủ Chúc Duẫn Minh và trưởng lão La Tòng Cương thuộc Thiên Cương Tông.","theLucLienQuan":[],"nguon":["@c1158"]},{"id":"chu-vi-dai-luc","name":"Chu Vĩ đại lục","cn":"","capDo":"khac","parentId":"van-hai-tinh","blurb":"Nơi sinh của Chu Thần, trưởng lão Thiên Cương Tông.","detail":"Chu Vĩ đại lục, nơi sinh của Chu Thần trước khi nửa đường gia nhập Thiên Cương Tông.","theLucLienQuan":[],"nguon":["@c1158"]},{"id":"dai-luc-hoang-da-ngu-giai","name":"Đại lục hoang dã sâu nhất ngũ giai tinh vực","cn":"","capDo":"khac","parentId":"ngu-giai-tinh-vuc","blurb":"Nơi Vương Lâm vọt ra trở về Vân Hải, có khe nứt từng tỏa bảy màu nay đã tắt.","detail":"Đại lục hoang dã nằm ở nơi sâu nhất ngũ giai tinh vực. Vương Lâm bị lực mạnh đẩy ra từ đây. Khe nứt trong đại lục từng tỏa bảy màu nhưng nay đã tắt.","theLucLienQuan":[],"nguon":["@c1158"]},{"id":"tinh-vuc-luc-giai","name":"Tinh vực lục giai","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp lục giai, nằm giữa ngũ giai và thất giai tinh vực.","detail":"Vương Lâm phi hành tốc độ cực hạn xuyên qua tinh vực lục giai. Các lão quái trong lục giai chấn động nhưng không ai dám ngăn cản, hơn mười lão quái bám theo phía sau xa xa để quan sát.","theLucLienQuan":[],"nguon":["@c1160"]},{"id":"tinh-vuc-that-giai","name":"Tinh vực thất giai","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp thất giai, ở trạng thái nửa phong tỏa với đại trận hình tròn bảo vệ.","detail":"Tinh vực thất giai đang ở trạng thái nửa phong tỏa, có đại trận phong tỏa hình tròn do nhiều tu sĩ trông coi. Cao thủ đông đảo vượt xa lục giai, có nhiều tu sĩ Toái Niết trấn thủ. Vương Lâm phá trận xông vào, dùng Dịch Linh Ấn mở đường xuyên qua trong gần mười ngày.","theLucLienQuan":[],"nguon":["@c1160"]},{"id":"tinh-vuc-bat-giai","name":"Tinh vực bát giai","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp bát giai, nơi có Phong Tiên giới.","detail":"Mục tiêu hành trình của Vương Lâm. Phong Tiên giới nằm tại tinh vực bát giai. Vương Lâm đã tới được sau gần mười ngày dùng Dịch Linh Ấn mở đường.","theLucLienQuan":[],"nguon":["@c1160"]},{"id":"phong-tien-gioi","name":"Phong Tiên giới","cn":"","capDo":"gioi-nho","parentId":"tinh-vuc-bat-giai","blurb":"Tiểu giới nằm ở tinh vực bát giai, mục tiêu hành trình của Vương Lâm.","detail":"Phong Tiên giới nằm ở tinh vực bát giai. Vương Lâm xuyên qua lục giai và thất giai tinh vực để tới đây.","theLucLienQuan":[],"nguon":["@c1160"]},{"id":"loan-thu-vu-gioi","name":"Loạn Thú Vụ Giới","cn":"亂獸霧界","capDo":"vuc","parentId":"van-hai-tinh","blurb":"Tầng sương mù dày đặc cực kỳ mênh mông bao quanh bát giai tinh vực, ngăn cách với tinh vực thất giai. Nơi hung hiểm bậc nhất Vân Hải tinh vực.","detail":"Bên trong mãnh thú phần lớn cấp mười trở lên, có cả mãnh thú cấp mười hai như rết lửa lam dài gần ngàn trượng. Thần Tông dùng phương pháp bí ẩn khiến mãnh thú không thể tùy tiện ra ngoài sương mù. Có bốn con đường an toàn do Thần Tông mở ra từ vô số năm trước, chỉ đệ tử tông phái bát giai tinh vực hoặc người có ngọc giản chỉ đường mới biết. Tu sĩ tầm thường vào thì chết, chỉ lão quái đại thần thông mới dám đi lại.","theLucLienQuan":["Thần Tông","Vô Cực Tông"],"nguon":["@c1161"]},{"id":"bat-giai-tinh-vuc","name":"Bát giai tinh vực","cn":"八阶星域","capDo":"vuc","parentId":"van-hai-tinh","blurb":"Tầng thứ tám của Vân Hải tinh vực, sương mù nồng đậm, nhiều lão quái đại thần thông. Chủ tông Vô Cực Tông đặt tại đây.","detail":"Vương Lâm tiến vào bát giai tinh vực sau khi rời Loạn Thú Vụ Giới. Nơi đây sương mù nồng đậm, nhiều lão quái đại thần thông (ví dụ lão già từng quan sát hắn giao chiến trong sương mù). Hắn phải thu liễm thân hình, giảm tốc, vòng tránh các tông phái. Chủ tông Vô Cực Tông đặt tại tầng này, tổ chức cuộc so tài phân tông.","theLucLienQuan":["Vô Cực Tông"],"nguon":["@c1163"]},{"id":"chien-truong-khe-yeu-tong","name":"Chiến trường khe bên ngoài Yêu Tông","capDo":"khac","parentId":"tinh-vuc-bat-giai","blurb":"Cái khe chiến trường bên ngoài Yêu Tông ở tầng thứ chín, nơi tu sĩ Vân Hải chống thú triều.","detail":"Chiến trường nơi Lý Thiến Mai chiến đấu chống thú triều, lau máu thú trên kiếm sau trận. Thú triều quy mô lớn hơn đang tới gần. Đại điện sơn môn Yêu Tông nằm phía trong.","theLucLienQuan":["Yêu Tông","Phá Thiên Tông"],"nguon":["@c1163"]},{"id":"dai-luc-hoang-da-van-hai","name":"Đại lục hoang dã (Vân Hải tinh vực)","capDo":"khac","parentId":"van-hai-tinh","blurb":"Đại lục hoang dã trong Vân Hải tinh vực, nơi Mộc Băng Mi ẩn trong động phủ trên đỉnh núi, giá lạnh tràn ngập.","detail":"Mộc Băng Mi ẩn náu trong động phủ trên đỉnh núi ở đại lục hoang dã này, thương thế nặng chưa hồi phục. Giá lạnh tràn ngập, sinh linh đều bị đông cứng. Vương San San tìm đến đây để đón nàng về Thần Tông.","theLucLienQuan":[],"nguon":["@c1163"]},{"id":"day-nui-ranh-gioi-van-thu-vuong","name":"Dãy núi khổng lồ (Phong Tiên Giới)","cn":"","capDo":"khac","parentId":"phong-tien-gioi","blurb":"Dãy núi cao chọc trời nằm ở rìa một mảnh vỡ đại lục trôi nổi trong Phong Tiên Giới, là lãnh địa của một Văn Thú Vương khác.","detail":"Bên ngoài dãy núi có vài nghìn Văn Thú đỏ và vài trăm Văn Thú lam canh giữ. Sâu bên trong gần vách núi có hai con Văn Thú trắng — cấp bậc cao hơn Văn Thú lam — bám trên vách núi, xúc tu không ngừng cọ vào vách núi phát ra tiếng kêu chói tai.","theLucLienQuan":[],"nguon":["@c1167"]},{"id":"day-nui-vung-van-thu","name":"Dãy núi vùng Văn Thú","cn":"","capDo":"khac","parentId":"bat-giai-tinh-vuc","blurb":"Dãy núi ở tầng thứ tám tinh vực, nơi đàn Văn Thú cư ngụ theo phân tầng đẳng cấp.","detail":"Bên ngoài có Văn Thú màu đỏ bao quanh, gần hơn là mấy trăm con Văn Thú màu lam, bên trong sâu ẩn chứa Văn Thú Vương màu tím. Khi Văn Thú Vương tím xuất hiện, dãy núi nứt từ đỉnh đến chân, sương tím tràn ra.","theLucLienQuan":[],"nguon":["@c1168"]}]};
